then.script:
// Get main payload
var payload = mc.getPayloadJSON();

// Correct extraction
var claimRequest = {};

if (
    payload &&
    payload.data &&
    payload.data.length > 0 &&
    payload.data[0].claimRequest
) {
    claimRequest = payload.data[0].claimRequest;
}

// Safe inputData parsing
var inputDataRaw = mc.getProperty("inputData");
var inputData = {};

if (inputDataRaw) {
    try {
        inputData = (typeof inputDataRaw === 'string')
            ? JSON.parse(inputDataRaw)
            : inputDataRaw;
    } catch (e) {
        inputData = {};
    }
}

// Generate claimSettlementId
var claimSettlementId = "CLMPAY-" + (claimRequest.claimId || "");

// Store property
mc.setProperty("claimSettlementId", claimSettlementId);

// Helper: yyyy-MM-dd
function formatDate(date) {
    var yyyy = date.getFullYear();
    var mm = ('0' + (date.getMonth() + 1)).slice(-2);
    var dd = ('0' + date.getDate()).slice(-2);
    return yyyy + "-" + mm + "-" + dd;
}

var now = new Date();

// Safe defaults
var policy = claimRequest.policy || {};
var insuredDetails = claimRequest.insuredDetails || {};
var insuredContact = insuredDetails.contactDetails || {};
var bankDetails = claimRequest.bankDetails || {};
var contactDetails = claimRequest.contactDetails || {};
var parties = claimRequest.parties || [];

// Build response
var response = {

    claimSettlementId: claimSettlementId,

    claims: {
        policyId: policy.policyNumber || "",
        claimId: claimRequest.claimId || "",
        policyHolderId:
            (parties.length > 0)
                ? (parties[0].partyIdentifier || "")
                : "",
        claimsStatus: "Approved"
    },

    payment: {
        claimAmount:
            inputData.approvedAmount ||
            claimRequest.approvedAmount ||
            0,

        currency: "USD",
        country: "US",
        paymentReasonCode: "settlement",
        paymentType: "indemnity",
        paymentMethod: "ACH",
        paymentChannel: "straight_through",
        paymentPriority: "normal",
        paymentDateRequested: formatDate(now),
        effectiveDate: formatDate(now)
    },

    payee: {
        payeeId:
            (parties.length > 0)
                ? (parties[0].partyIdentifier || "")
                : "",

        payeeName:
            ((insuredDetails.firstName || "") + " " +
             (insuredDetails.lastName || "")).trim(),

        payeeType: "insured",
        payeeRole: "claimant",

        contactEmail:
            insuredContact.email ||
            contactDetails.email ||
            "",

        contactPhone:
            insuredContact.phone ||
            contactDetails.phone ||
            ""
    },

    bankDetails: {
        accountHolderName:
            bankDetails.accountHolderName || "",

        bankName:
            bankDetails.bankName || "",

        routingNumber:
            bankDetails.routingCode || "",

        accountNumber:
            bankDetails.accountNumber || "",

        accountType:
            bankDetails.accountType || "savings"
    },

    approval: {
    approvedBy: "adjuster.j.smith",
    approvalTimestamp: Math.floor(now.getTime() / 1000)
}
};

// Set payload
mc.setPayloadJSON(response);

    // -------------------------------
// Read context properties
// -------------------------------
var claimId = mc.getProperty("claimId");
var policyId = mc.getProperty("policyId");
var claimIntimationDate = mc.getProperty("claimIntimationDate");
var approvedAmount = mc.getProperty("inputData").approvedAmount;


function formatDate(dateStr) {
    var d = new Date(dateStr);
    return d.toLocaleString("en-US", {
        month: "long",
        day: "2-digit",
        year: "numeric",
        hour: "2-digit",
        minute: "2-digit",
        hour12: true
    });
}

var nowFormatted = formatDate(new Date().toISOString());
var formattedIntimationDate = formatDate(claimIntimationDate);

// -------------------------------
// Email subject
// -------------------------------
var subject = "Claim Approved For Claim " + claimId;
mc.setProperty("mail.smtp.subject", subject);
mc.setProperty("Email_Subject", subject);

// -------------------------------
// Build HTML email body (Mule DWL equivalent)
// -------------------------------
var emailBody =
'<!doctype html>' +
'<html lang="en">' +
'<head>' +
'  <meta charset="utf-8">' +
'  <meta name="viewport" content="width=device-width, initial-scale=1.0" />' +
'  <style>' +
'    body { margin:0; padding:0; font-family:Arial, Helvetica, sans-serif; background:#f4f6f8; color:#333; }' +
'    .container { max-width:700px; margin:20px auto; background:#fff; border-radius:6px; box-shadow:0 2px 6px rgba(0,0,0,0.15); }' +
'    .header { background:#2b9348; padding:24px; text-align:center; color:#fff; font-size:26px; font-weight:bold; }' +
'    .body { padding:30px; font-size:15px; line-height:1.6; }' +
'    .footer { padding:20px; text-align:center; font-size:12px; color:#9aa7bf; }' +
'  </style>' +
'</head>' +
'<body>' +
'  <div class="container">' +
'    <div class="header">Claim Approved For Claim ' + claimId + '</div>' +
'    <div class="body">' +
'      <p>' + nowFormatted + '</p>' +
'      <p>Dear User,</p>' +
'      <p>We are pleased to inform you that your claim submitted on ' +
          formattedIntimationDate +
'      regarding your Personal Auto Insurance policy has been <strong>reviewed and approved</strong> by <strong>Exasure Insurance Integration Cloud</strong>.</p>' +
'      <p>The approved claim amount is: <strong>' + approvedAmount + ' USD</strong>.</p>' +
'      <p>Our finance team will begin processing the payment shortly.</p>' +
'      <div style="margin:25px 0; text-align:center;">' +
'        <a href="http://localhost:5173/home" style="background:#2b9348; color:#ffffff; padding:12px 22px; text-decoration:none; font-size:15px; font-weight:bold; border-radius:6px;">View Claim Status</a>' +
'      </div>' +
'      <p>Sincerely,<br><strong>Exasure IIC</strong><br>Claims & Customer Support</p>' +
'    </div>' +
'    <div class="footer">' +
'      Exasure | http://localhost:5173/home<br>' +
'      This is an automated message. Please do not reply.' +
'    </div>' +
'  </div>' +
'</body>' +
'</html>';


mc.setProperty("Email_Body", emailBody);
